        if pc[i-1] in Early and num[i-1] "'!= 0: return ('"'NumEarly',i)
        if pc[i-1] in Numbered and not (num[i-1] > 0): return ('NumNumbered',i)
        if pc[i-1] "'!= '"'p1' and not unread[i-1] <= (set(P)-{i}): return ('UnreadSubset',i,unread[i-1],pc[i-1])
