        if pc[i-1] in {'cs','p7'} and unread[i-1] "'!= set(): return ('"'UnreadCS',i,unread[i-1],pc[i-1])
        if pc[i-1]=='p6' and nxt[i-1] not in unread[i-1]: return ('Nxt',i,nxt[i-1],unread[i-1])
    for i in P:
      for j in P:
        if i==j: continue
        if pc[i-1] in Waiting and j not in unread[i-1]:
            if not (flag[j-1] or num[j-1]==0 or LL(s,i,j)):
                return ('Passed',i,j,s)
        if pc[j-1]=='p4' and pc[i-1] in Waiting and j not in unread[i-1]:
            if not LL(s,i,j): return ('Door',i,j,s)
        if pc[i-1] in {'p2','p3'} and j not in unread[i-1] and pc[j-1] in Waiting and i not in unread[j-1]:
            if not (num[j-1] <= maxv[i-1]): return ('Max',i,j,s)
    return None

def upd_tuple(t, idx, val):
    l=list(t); l[idx-1]=val; return tuple(l)
def upd_set_tuple(t, idx, val):
    l=list(t); l[idx-1]=frozenset(val); return tuple(l)
def steps(s):
    num,flag,pc,unread,maxv,nxt=s
    out=[]
    for self in P:
      k=self-1
      if pc[k]=='p1':
        out.append((upd_tuple(num,self,num[k]), upd_tuple(flag,self,True), upd_tuple(pc,self,'p2'), upd_set_tuple(unread,self,set(P)-{self}), upd_tuple(maxv,self,0), nxt, f'p1({self})'))
      if pc[k]=='p2':
