            newmax=upd_tuple(maxv,self,num[i-1]) if num[i-1]>maxv[k] else maxv
            out.append((num,flag,upd_tuple(pc,self,'p2'),newun,newmax,nxt,f'p2read({self},{i})'))
        else:
          out.append((num,flag,upd_tuple(pc,self,'p3'),unread,maxv,nxt,f'p2done({self})'))
      if pc[k]=='p3':
        out.append((upd_tuple(num,self,maxv[k]+1),flag,upd_tuple(pc,self,'p4'),unread,maxv,nxt,f'p3({self})'))
      if pc[k]=='p4':
        out.append((num,upd_tuple(flag,self,False),upd_tuple(pc,self,'p5'),upd_set_tuple(unread,self,set(P)-{self}),maxv,nxt,f'p4({self})'))
