      if pc[k]=='p6':
        j=nxt[k]
        if num[j-1]==0 or LL(s,self,j):
          out.append((num,flag,upd_tuple(pc,self,'p5'),upd_set_tuple(unread,self,set(unread[k])-{j}),maxv,nxt,f'p6({self},{j})'))
      if pc[k]=='cs':
        out.append((num,flag,upd_tuple(pc,self,'p7'),unread,maxv,nxt,f'cs({self})'))
      if pc[k]=='p7':
        out.append((upd_tuple(num,self,0),flag,upd_tuple(pc,self,'p1'),unread,maxv,nxt,f'p7({self})'))
